package problems;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class threeSum {

    public static void main(String[] args){
        int[] nums = {-1,0,1,2,-1,-4};
        System.out.println("Three Sum of array are " + threeSumList(nums));
    }

    public static List<List<Integer>> threeSumList(int[] nums) {
        // Sort array first to use two-pointer approach
        Arrays.sort(nums);
        List<List<Integer>> result = new ArrayList<>();

        // Iterate through array, fixing first element
        for (int i = 0; i < nums.length && nums[i] <= 0; i++) {
            // Skip duplicates for first element
            if (i == 0 || nums[i] != nums[i-1]) {
                twoSum(nums, i, result);
            }
        }

        return result;
    }

    static void twoSum(int[] nums, int i, List<List<Integer>> result) {
        int left = i + 1;
        int right = nums.length - 1;

        while (left < right) {
            int sum = nums[i] + nums[left] + nums[right];

            if (sum < 0) {
                left++;  // Need larger sum
            } else if (sum > 0) {
                right--;  // Need smaller sum
            } else {
                // Found triplet that sums to 0
                result.add(Arrays.asList(nums[i], nums[left++], nums[right--]));
                // Skip duplicates for left pointer
                while (left < right && nums[left] == nums[left-1]) {
                    left++;
                }
            }
        }
    }
}

// Time Complexity: O(n²) - O(n) for outer loop, O(n) for two-pointer
// Space Complexity: O(1) - not counting output array
